# type: ignore

  def run(self, args):
      if self.cmd_opts.get("compile"):
          if not self.compile_path:
              print("Error: --compile requires a compile path")
              return 1
          self.compile_path = self.compile_path.strip()
          if not self.compile_path.endswith(".py"):
              print("Error: --compile requires a .py file")
              return 1
          self.compile()
      else:
          if not self.compile_path:
              print("Error: --no-compile requires a compile path")
              return 1
          self.compile_path = self.compile_path.strip()
